  describe('isValidCertSerial', () => {
    it('should accept valid hex serials of 16+ chars', () => {
      expect(isValidCertSerial('aabbccddee112233')).toBe(true);
      expect(isValidCertSerial('AABBCCDDEE1122334455667788990011')).toBe(true);
