// Hash de IP con salt rotativo (privacy-preserving)
// ------------------------------------------------------------------
export function hashIp(ip: string, salt: string): string {
  return crypto.createHash('sha256').update(`${salt}:${ip}`).digest('hex').substring(0, 16);
}

