// ------------------------------------------------------------------
// Graceful shutdown
// ------------------------------------------------------------------
export async function closeConnections(): Promise<void> {
  if (redisInstance) {
    await redisInstance.quit();
    redisInstance = null;
  }
  if (sequelizeInstance) {
    await sequelizeInstance.close();
    sequelizeInstance = null;
  }
  console.log('[CONNECTIONS] All connections closed.');
}

