        },
      });

      return {
        success: true,
        token: accessToken,
        refreshToken,
        session_id: sessionId,
        fingerprint: fpHash,
      };
    } catch (err) {
      auditLogger.error('Authentication error', {
        actor_id: userId,
        client_ip: clientIp,
      });
      return { success: false, error: 'AUTH_INTERNAL_ERROR' };
    }
