      refreshTimerRef.current = setInterval(doRefresh, 4 * 60 * 1000);
    }
    return () => {
      if (refreshTimerRef.current) clearInterval(refreshTimerRef.current);
    };
  }, [state.isAuthenticated, state.refreshToken, doRefresh]);

  // ----------------------------------------------------------------
