export function sanitizeEmailBody(input: string): string {
  if (!input) return '';
  // Allow basic text but strip null bytes and control chars
  return input
    .replace(/\0/g, '')
    .replace(/[\x00-\x08\x0B-\x0C\x0E-\x1F\x7F]/g, '');
}

